import sys

class Solution:
    def rowWithMaxOnes(self, matrix: list[list[int]]) -> int:
        if not matrix:
            return -1
        m = len(matrix)
        n = len(matrix[0])
        max_row = -1
        j = n - 1
        for i in range(m):
            while j >= 0 and matrix[i][j] == 1:
                max_row = i
                j -= 1
        return max_row

