#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int rowWithMaxOnes(vector<vector<int>>& matrix) {
        int m = matrix.size();
        if (m == 0) return -1;
        int n = matrix[0].size();
        int maxRow = -1;
        int j = n - 1;
        for (int i = 0; i < m; ++i) {
            while (j >= 0 && matrix[i][j] == 1) {
                maxRow = i;
                --j;
            }
        }
        return maxRow;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int m, n;
    if (!(cin >> m >> n)) return 0;
    vector<vector<int>> matrix(m, vector<int>(n));
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            cin >> matrix[i][j];
        }
    }
    Solution sol;
    int ans = sol.rowWithMaxOnes(matrix);
    cout << ans << "\n";
    return 0;
}
